}
```

## Core Web Vitals 监控实现

### 使用 web-vitals 库（推荐）

```js
import { onLCP, onINP, onCLS, onFCP, onTTFB } from 'web-vitals'

function reportMetric({ name, value, rating, delta, id }) {
  analytics.track('web_vital', {
    metric_name: name, // 'LCP', 'INP', 'CLS', ...
    value: Math.round(name === 'CLS' ? value * 1000 : value),
    rating, // 'good', 'needs-improvement', 'poor'
    delta: Math.round(delta),
    metric_id: id,
  })
}

onLCP(reportMetric)
onINP(reportMetric)
onCLS(reportMetric)
onFCP(reportMetric)
onTTFB(reportMetric)
```

### 手动实现 LCP 采集

```js
// PerformanceObserver 监听 largest-contentful-paint
let lcp = null
const observer = new PerformanceObserver((list) => {
  const entries = list.getEntries()
  lcp = entries[entries.length - 1] // 取最新的（LCP 可能更新多次）
})
observer.observe({ type: 'largest-contentful-paint', buffered: true })

// 页面隐藏时上报最终值
document.addEventListener('visibilitychange', () => {
  if (document.visibilityState === 'hidden' && lcp) {
    report({ name: 'LCP', value: lcp.startTime, element: lcp.element?.tagName })
    observer.disconnect()
  }
})
```

### 手动实现 CLS 采集

```js
let clsValue = 0
let clsEntries = []
const clsObserver = new PerformanceObserver((list) => {
  list.getEntries().forEach((entry) => {
    // 用户交互后 500ms 内的偏移不计入 CLS
    if (!entry.hadRecentInput) {
      clsValue += entry.value
      clsEntries.push(entry)
    }
  })
})
clsObserver.observe({ type: 'layout-shift', buffered: true })
```

### 性能优化阈值

| 指标 | 良好    | 待改进   | 差       |
| ---- | ------- | -------- | -------- |
| LCP  | ≤ 2.5s  | ≤ 4.0s   | > 4.0s   |
| INP  | ≤ 200ms | ≤ 500ms  | > 500ms  |
| CLS  | ≤ 0.1   | ≤ 0.25   | > 0.25   |
| FCP  | ≤ 1.8s  | ≤ 3.0s   | > 3.0s   |
| TTFB | ≤ 800ms | ≤ 1800ms | > 1800ms |

## Rollup 打包组件库

### 为什么选 Rollup？

- Tree Shaking 更彻底（原生支持）
- 输出格式更干净（无 Webpack 的运行时代码）
- 适合库开发（ESM、CJS、UMD 多格式输出）

### rollup.config.js

```js
import resolve from '@rollup/plugin-node-resolve'
import commonjs from '@rollup/plugin-commonjs'
import typescript from '@rollup/plugin-typescript'
import dts from 'rollup-plugin-dts'
import { defineConfig } from 'rollup'

const pkg = require('./package.json')

export default defineConfig([
  // 主构建：输出 ESM 和 CJS
  {
    input: 'src/index.ts',
    output: [
      {
        file: pkg.module, // 'dist/index.esm.js'
        format: 'esm',
        sourcemap: true,
      },
      {
        file: pkg.main, // 'dist/index.cjs.js'
        format: 'cjs',
        sourcemap: true,
        exports: 'named',
      },
    ],
    plugins: [
      resolve(),
      commonjs(),
      typescript({ tsconfig: './tsconfig.json' }),
    ],
    // 声明外部依赖，不打进包里
    external: [
      'react',
      'react-dom',
      ...Object.keys(pkg.peerDependencies || {}),
    ],
  },
  // 类型声明文件
  {
    input: 'dist/types/index.d.ts',
    output: { file: 'dist/index.d.ts', format: 'esm' },
    plugins: [dts()],
  },
])
```

### package.json 配置

```json
{
  "name": "my-component-lib",
  "main": "dist/index.cjs.js",
  "module": "dist/index.esm.js",
  "types": "dist/index.d.ts",
  "exports": {
    ".": {
      "import": "./dist/index.esm.js",
      "require": "./dist/index.cjs.js",
      "types": "./dist/index.d.ts"
    }
  },
  "sideEffects": false,
  "files": ["dist"],
  "peerDependencies": {
    "react": ">=17"
  }
}
```

### 关键注意事项

1. `external` 声明 peer dependencies，避免重复打包
2. `sideEffects: false` 让消费方能 Tree Shaking
3. 同时输出 ESM（给打包工具）和 CJS（给 Node.js 环境）
4. 生成 `.d.ts` 类型声明文件
5. CSS 处理：用 `rollup-plugin-postcss` 可选是否注入或提取

## splitChunks 详解

### 默认行为

Webpack 5 默认只对异步 Chunk 进行分割，同步 Chunk 需要手动配置。

### 完整配置解析

```js
optimization: {
  splitChunks: {
    chunks: 'all',          // 'async'(默认) | 'initial' | 'all'
    minSize: 20000,         // 最小 20KB 才分割
    minChunks: 1,           // 至少被引用 1 次
    maxAsyncRequests: 30,   // 按需加载时最大并行请求数
    maxInitialRequests: 30, // 入口点最大并行请求数

    cacheGroups: {
      // 第三方库单独打包
      vendors: {
        test: /[\\/]node_modules[\\/]/,
        name: 'vendors',
        chunks: 'all',
        priority: -10,
        reuseExistingChunk: true,
      },

      // 大型库单独打包（减少 vendors 体积）
      react: {
        test: /[\\/]node_modules[\\/](react|react-dom)[\\/]/,
        name: 'react-vendor',
        chunks: 'all',
        priority: 20,     // 优先级高于 vendors
      },

      // 公共业务代码（被多个 Chunk 引用的）
      common: {
        name: 'common',
        minChunks: 2,       // 至少被 2 个 Chunk 引用
        priority: -20,
        reuseExistingChunk: true,
      },
    },
  },
}
```

### 分割策略建议

```
入口 Chunk（app.js）        ← 业务核心逻辑，频繁更新
react-vendor.js             ← React 相关，极少更新，长期缓存
vendors.js                  ← 其他 node_modules，较少更新
common.js                   ← 公共业务组件
page-home.js                ← 路由懒加载 Chunk
page-detail.js
```

**Hash 策略配合缓存：**

```js
output: {
  filename: '[name].[contenthash:8].js',  // 内容 hash，内容不变则缓存不失效
  chunkFilename: '[name].[contenthash:8].chunk.js',
}
```

## Service Worker 缓存策略

### 注册与生命周期

```js
// main.js
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker
      .register('/sw.js')
      .then((reg) => console.log('SW registered:', reg.scope))
      .catch((err) => console.error('SW failed:', err))
  })
}
```

### 缓存策略实现

```js
// sw.js
const CACHE_NAME = 'app-v1.2.0'
const STATIC_ASSETS = ['/index.html', '/app.js', '/styles.css']

// install：预缓存静态资源
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches
      .open(CACHE_NAME)
      .then((cache) => cache.addAll(STATIC_ASSETS))
      .then(() => self.skipWaiting()), // 立即激活新 SW
  )
})

// activate：清理旧缓存
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches
      .keys()
      .then((keys) =>
        Promise.all(
          keys.filter((k) => k !== CACHE_NAME).map((k) => caches.delete(k)),
        ),
      )
      .then(() => self.clients.claim()),
  )
})

// fetch：拦截请求，实现不同缓存策略
self.addEventListener('fetch', (event) => {
  const { request } = event
  const url = new URL(request.url)

  // API 请求：网络优先（Network First）
  if (url.pathname.startsWith('/api/')) {
    event.respondWith(networkFirst(request))
    return
  }

  // 静态资源：缓存优先（Cache First）
  event.respondWith(cacheFirst(request))
})

// 缓存优先策略
async function cacheFirst(request) {
  const cached = await caches.match(request)
  if (cached) return cached
  const response = await fetch(request)
  const cache = await caches.open(CACHE_NAME)
  cache.put(request, response.clone())
  return response
}

// 网络优先策略
async function networkFirst(request) {
  try {
    const response = await fetch(request)
    const cache = await caches.open(CACHE_NAME)
    cache.put(request, response.clone())
    return response
  } catch {
    return caches.match(request)
  }
}
```

### Workbox（推荐生产使用）

```js
// vite-plugin-pwa 配置
import { VitePWA } from 'vite-plugin-pwa'
plugins: [
  VitePWA({
    strategies: 'generateSW',
    workbox: {
      runtimeCaching: [
        {
          urlPattern: /^https:\/\/api\.example\.com\//,
          handler: 'NetworkFirst',
          options: {
            cacheName: 'api-cache',
            expiration: { maxAgeSeconds: 60 * 60 },
          },
        },
      ],
    },
  }),
]
```

## XSS 和 CSRF 防御实践

### XSS（跨站脚本）防御

**1. 输出转义（最基本）**

```js
// 永远不要直接将用户输入插入 HTML
// ❌ 危险
element.innerHTML = userInput

// ✅ 安全
element.textContent = userInput

// 需要富文本时，使用白名单过滤库
import DOMPurify from 'dompurify'
element.innerHTML = DOMPurify.sanitize(userInput, {
  ALLOWED_TAGS: ['p', 'b', 'i', 'a'],
  ALLOWED_ATTR: ['href'],
})
```

**2. CSP（内容安全策略）**

```http
Content-Security-Policy:
  default-src 'self';
  script-src 'self' 'nonce-{随机数}';
  style-src 'self' 'unsafe-inline';
  img-src 'self' data: https:;
  connect-src 'self' https://api.example.com;
  frame-ancestors 'none';
```

```html
<!-- CSP nonce：只允许带 nonce 的内联脚本执行 -->
<script nonce="r4nd0m">
  // 合法脚本
</script>
```

**3. React 中的 XSS**

```jsx
// React 默认转义，dangerouslySetInnerHTML 需要谨慎使用
// ❌
<div dangerouslySetInnerHTML={{ __html: userInput }} />

// ✅
<div dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(userInput) }} />
```

### CSRF（跨站请求伪造）防御

**1. CSRF Token（最常见）**

```js
// 服务端在 Cookie 或页面中设置随机 Token
// 前端请求时带上 Token（攻击者无法读取其他域的 Cookie）
axios.interceptors.request.use((config) => {
  const token =
    getCookie('csrf_token') ||
    document.querySelector('meta[name="csrf-token"]')?.content
  if (token) config.headers['X-CSRF-Token'] = token
  return config
})
```

**2. SameSite Cookie**

```http
Set-Cookie: session=abc; SameSite=Strict; Secure; HttpOnly
```

- `SameSite=Strict`：Cookie 不会随跨站请求发送
- `SameSite=Lax`：只有安全方法（GET）可以携带（默认值）

**3. 验证 Origin/Referer**

```js
// 服务端验证
app.use((req, res, next) => {
  const origin = req.headers.origin || req.headers.referer
  if (!origin?.startsWith('https://example.com')) {
    return res.status(403).json({ error: 'Invalid origin' })
  }
  next()
})
```

## 长列表性能优化

### 方案对比

| 方案     | 原理               | 优点         | 缺点                   |
| -------- | ------------------ | ------------ | ---------------------- |
| 分页     | 每次只加载 N 条    | 简单         | 用户体验差             |
| 无限滚动 | 滚动到底部加载更多 | 体验好       | 数据积累后仍有性能问题 |
| 虚拟滚动 | 只渲染可见区域 DOM | 根本解决方案 | 实现复杂               |

### 虚拟滚动实现（React）

**固定高度（最简单）：**

```tsx
import { useVirtualizer } from '@tanstack/react-virtual'

function VirtualList({ items }) {
  const parentRef = useRef(null)

  const virtualizer = useVirtualizer({
    count: items.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 50, // 每行 50px
    overscan: 5, // 可见区域外额外渲染 5 条
  })

  return (
    <div ref={parentRef} style={{ height: '600px', overflow: 'auto' }}>
      <div style={{ height: virtualizer.getTotalSize() }}>
        {virtualizer.getVirtualItems().map((virtualItem) => (
          <div
            key={virtualItem.key}
            style={{
              position: 'absolute',
              top: 0,
              transform: `translateY(${virtualItem.start}px)`,
              height: `${virtualItem.size}px`,
            }}
          >
            {items[virtualItem.index].name}
          </div>
        ))}
      </div>
    </div>
  )
}
```

**动态高度（测量实际高度）：**

```tsx
const virtualizer = useVirtualizer({
  count: items.length,
  getScrollElement: () => parentRef.current,
  estimateSize: () => 80, // 初始估算
  measureElement: (element) => element.getBoundingClientRect().height, // 测量实际高度
})
```

### 其他优化手段

**1. 时间切片（requestIdleCallback）**

```js
function processInChunks(items, processItem) {
  let index = 0
  function process(deadline) {
    while (index < items.length && deadline.timeRemaining() > 0) {
      processItem(items[index++])
    }
    if (index < items.length) requestIdleCallback(process)
  }
  requestIdleCallback(process)
}
```

**2. 减少重渲染（React.memo + key 稳定）**

```tsx
const Row = React.memo(({ item }) => <div>{item.name}</div>)

// key 必须稳定，不要用 index
items.map((item) => <Row key={item.id} item={item} />)
```

**3. Web Worker 处理数据**

```js
// 将排序、过滤等计算密集操作移到 Worker
const worker = new Worker('./list.worker.js')
worker.postMessage({ type: 'SORT', data: items, field: 'date' })
worker.onmessage = (e) => setSortedItems(e.data)
```

