### 领域实体示例

```ts
// domain/order/Order.ts
export class Order {
  private readonly id: string
  private items: OrderItem[]
  private status: OrderStatus

  constructor(params: { id: string; items: OrderItem[]; status: OrderStatus }) {
    this.id = params.id
    this.items = params.items
    this.status = params.status
  }

  // 领域行为（业务规则封装在实体内）
  addItem(item: OrderItem): void {
    if (this.status !== 'draft') throw new Error('只有草稿订单可以添加商品')
    if (this.items.length >= 100) throw new Error('订单商品不能超过100件')
    this.items.push(item)
  }

  cancel(): void {
    if (!['draft', 'pending'].includes(this.status)) {
      throw new Error(`${this.status} 状态的订单不能取消`)
    }
    this.status = 'cancelled'
  }

  get totalPrice(): number {
    return this.items.reduce((sum, item) => sum + item.price * item.quantity, 0)
  }
}
```

