```ts
// 页面由组件树描述，组件树可序列化为 JSON
interface ComponentSchema {
  id: string // 唯一 ID
  type: string // 组件类型（如 'Button', 'Input'）
  props: Record<string, unknown> // 组件属性
  children?: ComponentSchema[] // 子组件
  style?: React.CSSProperties // 样式
  events?: {
    // 事件绑定
    onClick?: ActionSchema
    onChange?: ActionSchema
  }
}

// 页面 Schema
interface PageSchema {
  id: string
  name: string
  components: ComponentSchema[] // 根组件列表
  dataBindings: DataBinding[] // 数据绑定
  variables: Variable[] // 页面变量
}
