### 核心模块

```ts
// 1. 渲染引擎：将 Schema 渲染为真实组件
function SchemaRenderer({ schema }: { schema: ComponentSchema }) {
  const Component = componentRegistry.get(schema.type);
  if (!Component) return <UnknownComponent type={schema.type} />;

  return (
    <Component {...schema.props} style={schema.style}>
      {schema.children?.map(child => (
        <SchemaRenderer key={child.id} schema={child} />
      ))}
    </Component>
  );
}

// 2. 组件注册中心
class ComponentRegistry {
  private map = new Map<string, ComponentDefinition>();

  register(name: string, def: ComponentDefinition) {
    this.map.set(name, def);
  }

  get(name: string) { return this.map.get(name)?.component; }
  getMeta(name: string) { return this.map.get(name)?.meta; } // 属性面板配置
}

// 3. 状态管理（编辑器核心状态）
interface EditorState {
  schema: PageSchema;
  selectedId: string | null;
  hoveredId: string | null;
  history: PageSchema[];  // undo/redo 历史
  clipboard: ComponentSchema | null;
}
