## Babel 插件开发

### Babel 插件基础

Babel 插件通过访问者模式（Visitor Pattern）遍历 AST 并转换节点。

```
源码字符串 → @babel/parser → AST → Babel Traverse（插件）→ @babel/generator → 新代码
```

### 实战：自动注入函数性能日志

**目标转换：**

```js
// 输入
function fetchUser(id) {
  return api.get('/user/' + id)
}

// 输出
function fetchUser(id) {
  const __start = performance.now()
  const __result = api.get('/user/' + id)
  console.log('[Perf] fetchUser:', performance.now() - __start, 'ms')
  return __result
}
```

**插件实现：**

```js
// babel-plugin-perf-logger.js
module.exports = function ({ types: t }) {
  return {
    visitor: {
      // 访问函数声明
      FunctionDeclaration(path) {
        const fnName = path.node.id?.name || 'anonymous'
        injectPerfLog(path, t, fnName)
      },
      // 访问箭头函数和函数表达式
      'ArrowFunctionExpression|FunctionExpression'(path) {
        const parent = path.parent
        const fnName =
          t.isVariableDeclarator(parent) && t.isIdentifier(parent.id)
            ? parent.id.name
            : 'anonymous'
        injectPerfLog(path, t, fnName)
      },
    },
  }
}

function injectPerfLog(path, t, fnName) {
  const body = path.get('body')
  if (!body.isBlockStatement()) {
    // 箭头函数简写形式，先转为块语句
    body.replaceWith(t.blockStatement([t.returnStatement(body.node)]))
  }

  const statements = body.get('body')
  if (!statements.length) return

  // 注入开始计时
  const startDecl = t.variableDeclaration('const', [
    t.variableDeclarator(
      t.identifier('__perfStart'),
      t.callExpression(
        t.memberExpression(t.identifier('performance'), t.identifier('now')),
        [],
      ),
    ),
  ])

  // 注入结束日志（在最后一个 return 前）
  const logStmt = t.expressionStatement(
    t.callExpression(
      t.memberExpression(t.identifier('console'), t.identifier('log')),
      [
        t.stringLiteral(`[Perf] ${fnName}:`),
        t.binaryExpression(
          '-',
          t.callExpression(
            t.memberExpression(
              t.identifier('performance'),
              t.identifier('now'),
            ),
            [],
          ),
          t.identifier('__perfStart'),
        ),
        t.stringLiteral('ms'),
      ],
    ),
  )

  body.unshiftContainer('body', startDecl)
  // 在每个 return 前插入日志
  body.traverse({
    ReturnStatement(returnPath) {
      returnPath.insertBefore(logStmt)
    },
  })
}
```

